# Import libraries
import time
import boto3
from selenium import webdriver
from selenium.webdriver.chrome.options import Options

# Set up Chrome options
chrome_options = Options()
chrome_options.add_argument("--headless")
chrome_options.add_argument("--disable-gpu")
chrome_options.add_argument("--no-sandbox")

# Initialize Chrome driver
driver = webdriver.Chrome(options=chrome_options)

# Function to take screenshot and save to S3
def take_screenshot(url, file_name):
    driver.get(url)
    time.sleep(5)  # Allowing time for the page to load completely
    driver.save_screenshot(file_name)
    
    # Upload screenshot to S3
    s3 = boto3.client('s3')
    s3.upload_file(file_name, 'your-s3-bucket-name', file_name)

# Example usage
url = 'https://www.example.com'
file_name = 'example_screenshot.png'
take_screenshot(url, file_name)

# Quit the driver
driver.quit()